/**
 * SMS notification channel — delivers notifications via SMS.
 *
 * In this implementation, sent messages are stored in-memory for
 * inspection and testing. A production implementation would use
 * an SMS gateway API (e.g. Twilio).
 */
export class SmsNotificationChannel implements NotificationChannel {
  readonly name = 'sms';
  private logger = new Logger('SmsChannel');
  private sentMessages: Notification[] = [];

  /** Deliver a notification as an SMS message. */
  send(notification: Notification): void {
    this.logger.info(
      `Sending SMS to ${notification.recipient}: ${notification.subject}`,
    );
    this.sentMessages.push({ ...notification });
  }

  /** Get all sent SMS messages. */
  getSentMessages(): Notification[] {
    return [...this.sentMessages];
  }

  /** Clear sent messages (useful for testing). */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

export interface WebhookDelivery {
  notification: Notification;
  url: string;
  deliveredAt: Date;
}

/**
 * Webhook notification channel — delivers notifications via HTTP webhooks.
 *
 * In this implementation, deliveries are stored in-memory for
 * inspection and testing. A production implementation would use
 * an HTTP client to POST to the configured URL.
 */
export class WebhookNotificationChannel implements NotificationChannel {
  readonly name = 'webhook';
  private logger = new Logger('WebhookChannel');
  private deliveries: WebhookDelivery[] = [];

  constructor(private webhookUrl: string) {}

  /** Deliver a notification via webhook POST. */
  send(notification: Notification): void {
    this.logger.info(
      `Sending webhook to ${this.webhookUrl} for ${notification.recipient}: ${notification.subject}`,
    );
    this.deliveries.push({
      notification: { ...notification },
      url: this.webhookUrl,
      deliveredAt: new Date(),
    });
  }

  /** Get all webhook deliveries. */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /** Clear deliveries (useful for testing). */
  clearDeliveries(): void {
    this.deliveries = [];
  }

  /** Get the configured webhook URL. */
  getWebhookUrl(): string {
    return this.webhookUrl;
  }
}

